```powershell
# Surveiller un processus et alerter
function Watch-Process {
    param(
        [string]$ProcessName,
        [int]$SeuilMo = 500,
        [int]$Secondes = 10
    )

    1..$Secondes | ForEach-Object {
        $p = Get-Process -Name $ProcessName -ErrorAction SilentlyContinue
        if ($null -eq $p) {
            Write-Warning "Processus $ProcessName introuvable"
            return
        }

        $ramMo = [math]::Round($p.WorkingSet / 1MB, 1)
        $cpu = [math]::Round($p.CPU, 1)

        if ($ramMo -gt $SeuilMo) {
            Write-Host "[ALERTE] RAM : ${ramMo}Mo" -ForegroundColor Red
        } else {
            Write-Host "[OK] $ProcessName — RAM: ${ramMo}Mo CPU: ${cpu}s"
        }
        Start-Sleep 1
    }
}

# Utilisation
Watch-Process -ProcessName "powershell" -SeuilMo 200 -Secondes 3

# Événements de processus avec WMI
Register-WmiEvent -Query "SELECT * FROM Win32_ProcessStartTrace" `
    -SourceIdentifier "NouveauProcessus" `
    -Action { Write-Host "Nouveau: $($event.SourceEventArgs.NewEvent.ProcessName)" }
